begin;
create table public.mission_events(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,mission_id uuid not null references public.missions(id) on delete cascade,event_type text not null check(event_type in('created','preferences_applied','options_prepared','recommendation_selected','customized','approved','execution_attempted','completed','failed','archived')),status text not null check(status in('pending','complete','failed','cancelled')),explanation text not null check(char_length(explanation)<=500),safe_metadata jsonb not null default '{}' check(pg_column_size(safe_metadata)<=8192),created_at timestamptz not null default now());
create table public.mission_receipts(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,mission_id uuid not null unique references public.missions(id) on delete cascade,confirmation_reference text not null,provider text not null,execution_status text not null check(execution_status in('demo_completed','failed','cancelled')),safe_summary jsonb not null check(pg_column_size(safe_summary)<=65536),confidence_score integer not null check(confidence_score between 0 and 100),created_at timestamptz not null default now(),deleted_at timestamptz);
create index mission_events_user_mission_idx on public.mission_events(user_id,mission_id,created_at);create index mission_receipts_user_created_idx on public.mission_receipts(user_id,created_at desc) where deleted_at is null;
alter table public.mission_events enable row level security;alter table public.mission_receipts enable row level security;
create policy mission_event_owner_select on public.mission_events for select using(user_id=auth.uid());create policy mission_receipt_owner_select on public.mission_receipts for select using(user_id=auth.uid());
revoke insert,update,delete on public.mission_events from authenticated;revoke insert,update,delete on public.mission_receipts from authenticated;grant select on public.mission_events,public.mission_receipts to authenticated;
commit;
